#include<bits/stdc++.h>
using namespace std;
int main() {
	string a;
	unsigned long long int c;
	long long n, m;
	cin >> n;
	for (long long i = 0; i < n; i++) {
		cin >> m;
		stack<unsigned long long int> b;//每次都要清空 
		for (long long j = 0; j < m; j++) {
			cin >> a;
			if (a == "push") {
				cin >> c;
				b.push(c);
			} else if (a == "pop") {
				if (b.empty()) {
					cout << "Empty" << endl;
				} else {
					b.pop();
				}
			} else if (a == "query") {
				if (b.empty()) {
					cout << "Anguei!" << endl;
				} else {
					cout << b.top() << endl;
				}
			} else if (a == "size") {
				cout << b.size() << endl;
			}
		}
	}
	return 0;
}
